- Simulate a long-running operation
- Progress bar updates incrementally
- Show percentage complete
- Cancel with Escape
- Success/failure indication

**Async Pattern**:
```rust
fn update(&mut self, msg: Msg) -> Cmd<Msg> {
    match msg {
        Msg::Start => {
            self.running = true;
            // Return command that performs work and sends progress
            Cmd::perform(
                async_work_simulation(),
                |result| Msg::Progress(result)
            )
        }
        Msg::Progress(pct) => {
            self.progress = pct;
            if pct >= 100 {
                Cmd::none()
            } else {
                Cmd::tick(Duration::from_millis(50), || Msg::Tick)
            }
        }
        // ...
    }
}
```

