### 1. CSI Sequence Generators
Generate valid CSI (Control Sequence Introducer) sequences:

```rust
use proptest::prelude::*;
use proptest::arbitrary::Arbitrary;

/// CSI sequence: ESC [ <params> <intermediate> <final>
#[derive(Debug, Clone)]
pub struct CsiSequence {
    pub params: Vec<u16>,
    pub intermediate: Option<u8>,
    pub final_byte: u8,
}

impl Arbitrary for CsiSequence {
    type Parameters = ();
    type Strategy = BoxedStrategy<Self>;

    fn arbitrary_with(_: Self::Parameters) -> Self::Strategy {
        (
            prop::collection::vec(0u16..=9999, 0..5),  // params
            prop::option::of(0x20u8..=0x2F),          // intermediate bytes
            0x40u8..=0x7E,                             // final byte
        )
            .prop_map(|(params, intermediate, final_byte)| {
                CsiSequence { params, intermediate, final_byte }
            })
            .boxed()
    }
}

impl CsiSequence {
    pub fn to_bytes(&self) -> Vec<u8> {
        let mut bytes = vec![0x1B, b'['];  // ESC [

        for (i, param) in self.params.iter().enumerate() {
            if i > 0 {
                bytes.push(b';');
            }
            bytes.extend(param.to_string().as_bytes());
        }

        if let Some(intermediate) = self.intermediate {
            bytes.push(intermediate);
        }

        bytes.push(self.final_byte);
        bytes
    }
}
```

