impl HeaderStyle {
    pub fn build_style(&self) -> Style {
        let mut style = self.cell_style.clone();

        if self.bold {
            style = style.bold(true);
        }

        if let Some(bg) = &self.background {
            style = style.background(bg.clone());
        }

        if let Some(fg) = &self.foreground {
            style = style.foreground(fg.clone());
        }

        style
    }

    pub fn apply_transform(&self, text: &str) -> String {
        match self.transform {
            TextTransform::None => text.to_string(),
            TextTransform::Uppercase => text.to_uppercase(),
            TextTransform::Lowercase => text.to_lowercase(),
            TextTransform::Capitalize => {
                let mut chars = text.chars();
                match chars.next() {
                    None => String::new(),
                    Some(c) => c.to_uppercase().chain(chars).collect(),
                }
            }
        }
    }
}

fn render_header_cell(content: &str, width: usize, alignment: Alignment, style: &HeaderStyle) -> String {
    let transformed = style.apply_transform(content);
    let padded = pad_content(&transformed, width, alignment);
    let cell_style = style.build_style().width((width + 2) as i32);  // +2 for padding

    cell_style.render(&format!(" {} ", padded))
}
