fn render_header_row(
    cells: &[TableCell],
    widths: &[usize],
    border: &TableBorder,
    style: &HeaderStyle,
) -> String {
    let header_style = style.build_style();
    let mut result = String::new();

    // Left border
    result.push_str(border.vertical);

    for (i, cell) in cells.iter().enumerate() {
        let content = style.apply_transform(&cell.content);
        let padded = pad_content(&content, widths[i], cell.alignment);

        // Apply style to cell content (including padding)
        let styled_cell = header_style.render(&format!(" {} ", padded));
        result.push_str(&styled_cell);

        result.push_str(border.vertical);
    }

    result
}
